        data.EXTI_Trigger = input.bytes[6] & 0x01 ? 'TRUE' : 'FALSE';
        data.Door_status = input.bytes[6] & 0x80 ? 'CLOSE' : 'OPEN';
        if (((input.bytes[9] << 8) | input.bytes[10]) === 0) {
