codecs.dragino/lbt1-codec:
function decodeUplink(input) {
  // Decode an uplink message from a buffer
  // (array) of bytes to an object of fields.
  var port = input.fPort;
  var bytes = input.bytes;
  var mode = bytes[5];
  var data = {};
  var i;
  var con;
  var str = '';
  var value = (bytes[0] << 8) | bytes[1];
  var addr = '';
  var rssi = 0;
  var major = 1;
  var minor = 1;

  switch (input.fPort) {
    case 2:
      if (mode == 2) {
        for (i = 38; i < 50; i++) {
          con = bytes[i].toString();
          str += String.fromCharCode(con);
        }

        data.addr = str;
        data.batV = value / 1000;
        data.major = 1;
        data.minor = 1;
        data.rssi = 0;

        str = '';

        for (i = 6; i < 38; i++) {
          con = bytes[i].toString();
          str += String.fromCharCode(con);
        }

        value = str;
      }

      if (mode == 3) {
        str = '';
        for (i = 18; i < 22; i++) {
          con = bytes[i].toString();
          str += String.fromCharCode(con);
        }

        data.major = parseInt(str, 16);
        data.batV = value / 1000;
        data.addr = '';

        str = '';

        for (i = 22; i < 26; i++) {
          con = bytes[i].toString();
          str += String.fromCharCode(con);
        }

        data.minor = parseInt(str, 16);

        str = '';

        for (i = 28; i < 32; i++) {
          con = bytes[i].toString();
          str += String.fromCharCode(con);
        }

        data.rssi = parseInt(str);

        str = '';
        for (i = 6; i < 18; i++) {
          con = bytes[i].toString();
          str += String.fromCharCode(con);
        }

        value = str;
      }

      if (mode == 1) {
        for (i = 6; i < 11; i++) {
          con = bytes[i].toString();
          str += String.fromCharCode(con);
        }
        data.batV = value / 1000;
        value = str;
        data.addr = '';
        data.major = 1;
        data.minor = 1;
        data.rssi = 0;
      }

      data.uuid = value;
      data.alarm = (bytes[2] >> 4) & 0x0f;
      data.step_count = ((bytes[2] & 0x0f) << 16) | (bytes[3] << 8) | bytes[4];
      return {
        data: data,
      };
    default:
      return {
        errors: ['unknown FPort'],
      };
  }
}

codecs.dragino/lse01-codec:
function decodeUplink(input) {
  var port = input.fPort;
  var bytes = input.bytes;
  var value = ((bytes[0] << 8) | bytes[1]) & 0x3fff;
  var batV = value / 1000; //Battery,units:V
  value = (bytes[2] << 8) | bytes[3];
  var data = {};
  switch (input.fPort) {
    case 2:
      if (bytes[2] & 0x80) {
        value |= 0xffff0000;
      }
      data.Bat = batV;
      data.TempC_DS18B20 = (value / 10).toFixed(1); //DS18B20,temperature,units:℃

      value = (bytes[4] << 8) | bytes[5];
      data.water_SOIL = (value / 100).toFixed(2); //water_SOIL,Humidity,units:%

      value = (bytes[6] << 8) | bytes[7];
      if ((value & 0x8000) >> 15 === 0)
        data.temp_SOIL = (value / 100).toFixed(2); //temp_SOIL,temperature,units:°C
      else if ((value & 0x8000) >> 15 === 1) data.temp_SOIL = ((value - 0xffff) / 100).toFixed(2); //temp_SOIL,temperature,units:°C

      value = (bytes[8] << 8) | bytes[9];
      data.conduct_SOIL = value; //conduct_SOIL,conductivity,units:uS/cm

      return {
        data: data,
      };
    default:
      return {
        errors: ['unknown FPort'],
      };
  }
}

function normalizeUplink(input) {
  var data = {};
  var air = {};
  var soil = {};

  if (input.data.TempC_DS18B20) {
    air.temperature = Number(input.data.TempC_DS18B20);
  }

  if (input.data.temp_SOIL) {
    soil.temperature = Number(input.data.temp_SOIL);
  }

  if (input.data.water_SOIL) {
    soil.moisture = Number(input.data.water_SOIL);
  }

  if (input.data.conduct_SOIL) {
    soil.ec = input.data.conduct_SOIL / 1000;
  }

  if (Object.keys(air).length > 0) {
    data.air = air;
  }

  if (Object.keys(soil).length > 0) {
    data.soil = soil;
  }

  if (input.data.Bat) {
    data.battery = input.data.Bat;
  }

  return { data: data };
}

